import {
	DeleteItemCommand,
	DynamoDBClient,
	GetItemCommand,
} from '@aws-sdk/client-dynamodb';
import { getTenantContext, createResponse } from 'tenant-utils';

const dynamodb = new DynamoDBClient({ region: process.env.AWS_REGION });

export const handler = async (event) => {

	console.info("EVENT\n" + JSON.stringify(event, null, 2));

	try {
		// Extract tenant context from request
		const tenantContext = await getTenantContext(event);
		console.log('Tenant context:', tenantContext);

		const payload = JSON.parse(event.body);


		const params = {
			TableName: tenantContext.tableNames.sessionIdTable,
			Key: {
				uuid: { S: payload.uuid },
			},
		};

		try {
			const getItemCommand = new GetItemCommand(params);
			const results = await dynamodb.send(getItemCommand);
			console.log(`[Tenant: ${tenantContext.tenantId}] removeuuid, get uuid result:`, results);

			const email = results.Item.username.S;
			const apti = results.Item.apti.S;

			if (email.trim().toLowerCase() === payload.email.trim().toLowerCase() &&
				(apti === payload.apti || apti === 'updateprofile')) {

				//delete the pwd reset session id once reset is done successfully.
				const deleteItemCommand = new DeleteItemCommand(params);
				const res = await dynamodb.send(deleteItemCommand);

				console.log(`[Tenant: ${tenantContext.tenantId}] removeuuid, delete uuid result:`, res);

				return createResponse(200, { message: 'success' }, tenantContext.tenantId);
			}
		}
		catch (error) {
			console.log(`[Tenant: ${tenantContext.tenantId}] error:`, error);
			return createResponse(500, error, tenantContext.tenantId);
		}

		return createResponse(501, { message: 'not found' }, tenantContext.tenantId);

	} catch (e) {
		console.log('Catch an error: ', e);
		
		// Try to get tenant ID for error response
		let tenantId = null;
		try {
			const tenantContext = await getTenantContext(event);
			tenantId = tenantContext.tenantId;
		} catch (tenantError) {
			console.log('Could not extract tenant ID for error response:', tenantError.message);
		}
		
		return createResponse(500, { message: 'signout error' }, tenantId);
	}
}
